def _binary_search(arr, x, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == x:
            return mid
        elif arr[mid] < x:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def exponential_search(arr, x):
    n = len(arr)

    if n == 0:
        return -1

    if arr[0] == x:
        return 0

    i = 1
    while i < n and arr[i] <= x:
        i *= 2

    return _binary_search(arr, x, i // 2, min(i, n - 1))
